5	const PROCESSING_FEE = 5;
6	const FIRST_INSURANCE_SURCHARGE = 1.1;
7	
8	const BASE_PREMIUMS: Record<string, number> = {
9	  sword: 100,
10	  amulet: 60,
11	};
12	
13	function roundUpToWholeG(amount: number): number {
14	  // Round to cents first to avoid float-precision artifacts like 100*1.10 = 110.00000000000001
15	  return Math.ceil(Math.round(amount * 100) / 100);
16	}
17	
18	export function quote(
19	  _customer: { yearsWithMHPCO: number },
20	  items: Item[],
21	  _previousContracts?: number,
22	): number {
23	  if (items.length === 0) return PROCESSING_FEE;
24	  const basePremium = BASE_PREMIUMS[items[0].type];
25	  const premium = roundUpToWholeG(basePremium * FIRST_INSURANCE_SURCHARGE);
26	  return premium + PROCESSING_FEE;
27	}
